from collections import defaultdict

class Solution(object):
    def score(self, cards, x):
        both = 0
        cnt1 = defaultdict(int)  # x at pos 0, other letter at pos 1
        cnt2 = defaultdict(int)  # other letter at pos 0, x at pos 1

        for card in cards:
            has0 = card[0] == x
            has1 = card[1] == x
            if has0 and has1:
                both += 1
            elif has0:
                cnt1[card[1]] += 1
            elif has1:
                cnt2[card[0]] += 1

        def solve(cnt, have):
            if not cnt:
                return 0
            total = sum(cnt.values())
            M = max(cnt.values())
            rest = total - M
            if have < M - rest:
                # Not enough wildcards to balance the dominant letter
                return have + rest
            else:
                w = min(have, total)
                return w + (total - w) // 2

        ans = 0
        for i in range(both + 1):
            ans = max(ans, solve(cnt1, i) + solve(cnt2, both - i))
        return ans
